from dataclasses import dataclass, field
from enum import Enum
from typing import Dict, List, Optional
import datetime


class ActionPriority(Enum):
    CRITICAL = 1   # Blocks quality gate; must be this sprint
    HIGH     = 2   # Significant regression risk; this or next sprint
    MEDIUM   = 3   # Backlog; reviewed quarterly
    LOW      = 4   # Nice-to-have; retire if stale


@dataclass
class ImprovementBacklog:
    team_id: str
    items: List[RetroActionItem] = field(default_factory=list)

    def open_items(self) -> List[RetroActionItem]:
        terminal = {ActionItemState.VERIFIED, ActionItemState.CANCELLED}
        return [i for i in self.items if i.state not in terminal]

    def overdue(self, current_sprint: str) -> List[RetroActionItem]:
        return [
            i for i in self.open_items()
            if i.target_sprint < current_sprint
            and i.state not in {ActionItemState.DEFERRED, ActionItemState.VERIFIED, ActionItemState.CANCELLED}
        ]

    def escalations_needed(self) -> List[RetroActionItem]:
        return [i for i in self.open_items() if i.needs_escalation()]

    def sprint_candidates(
        self, sprint_id: str, max_items: int = 3
    ) -> List[RetroActionItem]:
        """Items to bring into sprint planning."""
        candidates = [
            i for i in self.open_items()
            if i.state in {ActionItemState.IDENTIFIED, ActionItemState.DEFERRED}
        ]
        return sorted(candidates, key=lambda i: i.target_sprint)[:max_items]

    def closure_rate_last_n_sprints(self, n: int) -> float:
        """Fraction of items from the last N sprints that reached VERIFIED."""
        relevant = [
            i for i in self.items
            if i.state in {ActionItemState.VERIFIED, ActionItemState.CANCELLED}
        ][-n * 3:]  # approximate; assumes ~3 items per sprint
        if not relevant:
            return 0.0
        verified = sum(1 for i in relevant if i.state == ActionItemState.VERIFIED)
        return verified / len(relevant)

    def backlog_health_report(self, current_sprint: str) -> str:
        open_items = self.open_items()
        overdue = self.overdue(current_sprint)
        escalations = self.escalations_needed()
        closure = self.closure_rate_last_n_sprints(4)
        return (
            f"Improvement Backlog Health [{self.team_id}]\n"
            f"  Open: {len(open_items)} | Overdue: {len(overdue)} | Escalations: {len(escalations)}\n"
            f"  Closure rate (last 4 sprints): {closure:.0%}\n"
            + ("  WARN: Closure rate below 70% — improvement work is not being resourced.\n"
               if closure < 0.7 else "")
            + ("  WARN: " + str(len(escalations)) + " item(s) deferred 3+ times — tech lead review needed.\n"
               if escalations else "")
        )

from dataclasses import dataclass
from typing import List, Optional
import datetime


@dataclass
class VerificationEvidence:
    action_item_id: str
    success_metric: str        # The metric specified when the action was identified
    metric_value_before: float
    metric_value_after: float
    measurement_window_sprints: int   # How many sprints of post-fix data was collected
    verified_by: str
    verified_at: str           # ISO-8601
    notes: str = ""

    def improvement_pct(self) -> float:
        if self.metric_value_before == 0:
            return 0.0
        return (self.metric_value_before - self.metric_value_after) / self.metric_value_before

    def is_resolved(self, min_improvement_pct: float = 0.2) -> bool:
        """True if the metric improved by at least min_improvement_pct."""
        return self.improvement_pct() >= min_improvement_pct

    def verification_summary(self) -> str:
        resolved = "RESOLVED" if self.is_resolved() else "INSUFFICIENT IMPROVEMENT"
        return (
            f"[{self.action_item_id}] Verification: {resolved}\n"
            f"  Metric: {self.success_metric}\n"
            f"  Before: {self.metric_value_before:.3f} | After: {self.metric_value_after:.3f} "
            f"| Improvement: {self.improvement_pct():.0%}\n"
            f"  Measurement window: {self.measurement_window_sprints} sprint(s)\n"
            f"  Verified by: {self.verified_by} at {self.verified_at}"
        )


@dataclass
class VerificationProtocol:
    min_measurement_window_sprints: int = 2   # Wait at least 2 sprints before verifying
    min_improvement_pct: float = 0.20         # At least 20% improvement required
    reopen_threshold_pct: float = 0.50        # Reopen if metric deteriorates > 50%

    def can_verify(
        self, action_item: RetroActionItem, current_sprint: str
    ) -> bool:
        """True if enough time has elapsed since the action was completed."""
        done_events = [
            t for t in action_item.history
            if t.to_state == ActionItemState.DONE
        ]
        if not done_events:
            return False
        done_sprint = action_item.target_sprint   # approximate
        age = max(0, ord(current_sprint[-1]) - ord(done_sprint[-1]))
        return age >= self.min_measurement_window_sprints

    def should_reopen(
        self, evidence: VerificationEvidence, current_metric: float
    ) -> bool:
        """True if a previously verified action's metric has deteriorated."""
        return (
            current_metric > evidence.metric_value_after * (1 + self.reopen_threshold_pct)
        )
